. "$env:userprofile/.platformio/penv/Scripts/activate.ps1"; $argEnv=if($args.Count -gt 0 -and -not [string]::IsNullOrWhiteSpace($args[0])){ $args[0].Trim() } else { $null }; $lastBuilt=Get-ChildItem '.pio/build' -Directory -ErrorAction SilentlyContinue | Sort-Object LastWriteTime -Descending | Select-Object -First 1 -ExpandProperty Name; $m=Select-String -Path 'platformio.ini' -Pattern '^\s*default_envs\s*=\s*(.+)$' | Select-Object -First 1; $defaultEnv=if($m){ ($m.Matches[0].Groups[1].Value -split ',')[0].Trim() } else { $null }; $envName=if($argEnv){$argEnv}elseif($lastBuilt){$lastBuilt}elseif($defaultEnv){$defaultEnv}else{'adafruit_qualia_s3_rgb666'}; Write-Host "Using env: $envName"; $kErase=$null; $kClean=$null; $sw=[Diagnostics.Stopwatch]::StartNew(); Write-Host 'Press E within 2s to erase flash (default: no)...'; while($sw.ElapsedMilliseconds -lt 2000 -and -not $kErase){ if([Console]::KeyAvailable){ $kErase=[Console]::ReadKey($true).KeyChar } else { Start-Sleep -Milliseconds 50 } }; Write-Host 'Press F within 1.5s for fullclean, C for clean (default: none)...'; $sw.Restart(); while($sw.ElapsedMilliseconds -lt 1500 -and -not $kClean){ if([Console]::KeyAvailable){ $kClean=[Console]::ReadKey($true).KeyChar } else { Start-Sleep -Milliseconds 50 } }; if($kClean -match '^[fF]$'){ pio run -t fullclean -e $envName } elseif($kClean -match '^[cC]$'){ pio run -t clean -e $envName }; if($kErase -match '^[eE]$'){ pio run -t erase -e $envName }; pio run -t upload -e $envName